import{c as t,Q as a,j as o,m as r}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Installation Overview","description":"","frontmatter":{},"headers":[],"relativePath":"installation/index.md","filePath":"installation/index.md","lastUpdated":1780209430000}'),l={name:"installation/index.md"};function s(n,e,i,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="installation-overview" tabindex="-1">Installation Overview <a class="header-anchor" href="#installation-overview" aria-label="Permalink to &quot;Installation Overview&quot;">​</a></h1><p>Memoh is distributed in two forms: a native desktop client for personal/local use, and a server deploy stack for always-on shared usage. Choose the one that matches how you want bots to run.</p><table tabindex="0"><thead><tr><th>Use case</th><th>Choose</th><th>Why</th></tr></thead><tbody><tr><td>Personal desktop workflow, local memory, quick trial, single-user usage</td><td><a href="/installation/desktop.html">Desktop</a></td><td>The app starts and stops its own local server, embedded Qdrant, local storage, and bundled CLI.</td></tr><tr><td>Shared server, remote access, public/private channels, production uptime, multi-user or multi-tenant usage</td><td><a href="/installation/docker.html">Server Deploy</a></td><td>The Docker Compose stack keeps the backend, Web UI, database, memory services, and workspace runtime online.</td></tr></tbody></table><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to &quot;Desktop&quot;">​</a></h2><p>Use Desktop when you want Memoh to behave like a local app. It manages a local <code>memoh-server</code> on <code>127.0.0.1:18731</code>, prepares local storage, starts embedded Qdrant for memory search, and connects the UI automatically.</p><p>Desktop is the easiest path for trying Memoh on your own computer. It is not the right choice for bots that must keep serving external channels while your computer is offline.</p><h2 id="server-deploy" tabindex="-1">Server Deploy <a class="header-anchor" href="#server-deploy" aria-label="Permalink to &quot;Server Deploy&quot;">​</a></h2><p>Use Server Deploy when Memoh should be reachable by multiple users, run continuously, or connect to external channels such as Telegram, Discord, Lark, WeChat, WeChat Official Account, Email, and more.</p><p>Start with <a href="/installation/docker.html">Server Deploy</a> for a Docker Compose deployment.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/installation/workspace-backends.html">Workspace Backends</a> explains Docker, containerd, Apple, and local workspace runtime choices.</li><li><a href="/installation/sqlite.html">SQLite deployment</a> covers lighter single-node server deployments.</li></ul>',11)])])}const u=t(l,[["render",s]]);export{m as __pageData,u as default};
